class t{loaderElement;static get classes(){return{isLoaded:"is-loaded"}}constructor(){this.loaderElement=document.querySelector("[data-loader]"),this.loaderElement&&this.init()}init(){console.log("Loader"),window.addEventListener("load",async()=>{history.scrollRestoration="manual",await this.addClass(),await this.removeElement()})}addClass(){return new Promise(e=>{document.documentElement.classList.add(t.classes.isLoaded),e()})}removeElement(){return new Promise(e=>{setTimeout(()=>this.loaderElement.remove(),500),e()})}}class s{constructor(){this.init()}init(){console.log("app"),Promise.all([new t]).then(()=>{})}}window.addEventListener("DOMContentLoaded",()=>{console.log("main.ts"),new s});
